using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with a default resolver so metadata is generated for known types.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new DefaultJsonTypeInfoResolver())
};

// ──────────────────────────────────────────────────────────────────────
// 1. Get strongly-typed JsonTypeInfo<T> (throws if unavailable)
// ──────────────────────────────────────────────────────────────────────
JsonTypeInfo<Person> typedInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<Person>: Kind={typedInfo.Kind}, Type={typedInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), typedInfo);
Console.WriteLine($"Serialized: {json}");

// ──────────────────────────────────────────────────────────────────────
// 2. Probe without throwing — TryGetTypeInfo
// ──────────────────────────────────────────────────────────────────────
if (options.TryGetTypeInfo<Secret>(out JsonTypeInfo<Secret>? secretInfo))
{
    Console.WriteLine($"Secret metadata available: {secretInfo.Type.Name}");
}
else
{
    Console.WriteLine("Secret metadata NOT available (no exception thrown).");
}

// Also show that it works when the type IS resolvable:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? personInfo))
{
    Console.WriteLine($"Person metadata available via TryGet: Kind={personInfo.Kind}");
}

// ──────────────────────────────────────────────────────────────────────
public record Person(string Name, int Age);

// A type whose metadata is intentionally unresolvable (resolver returns null).
public class Secret { }

